386: export fn add(state: *anyopaque, char_code: u16) u8 {
387:     const s: *State = @ptrCast(@alignCast(state));
388: 
389:     // Only handle ASCII range
390:     if (char_code > 127) {
391:         reset(state);
392:         return 0;
393:     }
394:     const ch: u8 = @intCast(char_code);
395: 
396:     // Non-alphanumeric ŌåÆ reset and passthrough
397:     if (!isAlpha(ch)) {
