429:             const last = &s.spans[last_idx];
430:             if (toLower(last.base) == 'd' and last.modifier == 0) {
431:                 // Cancellation: if already ─æ, undo
432:                 if (last.modifier == 'd') {
433:                     // Already handled above: modifier is 0 here
434:                     unreachable;
435:                 }
436:                 last.modifier = 'd';
437:                 return 1;
438:             }
439:         }
440:         // Regular d consonant
441:         if (!appendSpan(s, ch, 0, 0, flags)) return overflowReset(s);
442:         autoFillUO(s);
443:         return 1;
