456:                     if (!appendSpan(s, ch, 0, 0, flags)) return overflowReset(s);
457:                     return 1;
458:                 }
459:                 if (last.modifier == 0) {
460:                     last.modifier = lo;
461:                     return 1;
462:                 }
463:             }
464:         }
465:     }
